let webProcs = dynamic(["w3wp.exe","httpd.exe","nginx.exe","tomcat.exe","java.exe"]);
let shellProcs = dynamic(["cmd.exe","powershell.exe","pwsh.exe","net.exe","net1.exe","whoami.exe","nltest.exe","ipconfig.exe","systeminfo.exe","reg.exe","tasklist.exe"]);
let shellExt = dynamic([".aspx",".asp",".ashx",".asmx",".php",".jsp",".jspx"]);
let webPaths = dynamic([@"\inetpub\wwwroot\", @"\wwwroot\", "/htdocs/","/webapps/","/var/www/"]);
let shellWrites =
  DeviceFileEvents
  | where Timestamp > ago(7d)
  | where InitiatingProcessFileName in~ (webProcs)
  | where FileName has_any (shellExt)
  | where FolderPath has_any (webPaths)
  | project ShellTime=Timestamp, DeviceId, DeviceName, ShellFile=FolderPath, ShellName=FileName, WebProc=InitiatingProcessFileName, ShellInitiator=InitiatingProcessId;
let shellSpawns =
  DeviceProcessEvents
  | where Timestamp > ago(7d)
  | where InitiatingProcessFileName in~ (webProcs)
  | where FileName in~ (shellProcs)
  | project SpawnTime=Timestamp, DeviceId, DeviceName, ChildProc=FileName, ChildCmd=ProcessCommandLine, ParentProc=InitiatingProcessFileName, AccountName;
shellWrites
| join kind=inner (shellSpawns) on DeviceId
| where SpawnTime between (ShellTime .. ShellTime + 30m)
| project ShellTime, SpawnTime, DeviceName, AccountName, WebProc, ShellFile, ShellName, ChildProc, ChildCmd
| sort by ShellTime desc
